          natural_languages == other.natural_languages &&
          percentile_computation == other.percentile_computation &&
          explain == other.explain
      end

      # @see the `==` method
      # @param [Object] Object to be compared
      def eql?(other)
        self == other
      end

      # Calculates hash code according to all attributes.
      # @return [Integer] Hash code
      def hash
        [
          query_type,
          similar_query,
          query_languages,
          advanced_syntax,
          advanced_syntax_features,
          alternatives_as_exact,
          decompound_query,
          typo_tolerance,
          allow_typos_on_numeric_tokens,
          min_word_size_for1_typo,
          min_word_size_for2_typos,
          disable_typo_tolerance_on_attributes,
          filters,
          facet_filters,
          facets,
          max_values_per_facet,
          max_facet_hits,
          faceting_after_distinct,
          sort_facet_values_by,
          numeric_filters,
          tag_filters,
          sum_or_filters_scores,
          around_lat_lng,
          around_lat_lng_via_ip,
          around_radius,
          around_precision,
          minimum_around_radius,
          inside_bounding_box,
          inside_polygon,
          attributes_to_retrieve,
          attributes_to_snippet,
          snippet_ellipsis_text,
          restrict_highlight_and_snippet_arrays,
          page,
          offset,
          hits_per_page,
          length,
          get_ranking_info,
          relevancy_strictness,
          min_proximity,
          attribute_criteria_computed_by_min_proximity,
          distinct,
          enable_rules,
          enable_personalization,
          personalization_impact,
          enable_ab_test,
          enable_re_ranking,
          re_ranking_apply_filter,
          rule_contexts,
          remove_stop_words,
          ignore_plurals,
          remove_words_if_no_results,
          optional_words,
          optional_filters,
          synonyms,
          replace_synonyms_in_highlight,
          analytics,
          analytics_tags,
          click_analytics,
          user_token,
          restrict_searchable_attributes,
          disable_exact_on_attributes,
          exact_on_single_word_query,
          natural_languages,
          percentile_computation,
          explain
        ].hash
      end

      # Builds the object from hash
      # @param [Hash] attributes Model attributes in the form of hash
      # @return [Object] Returns the model itself
      def self.build_from_hash(attributes)
        return nil unless attributes.is_a?(Hash)
        attributes = attributes.transform_keys(&:to_sym)
        transformed_hash = {}
        types_mapping.each_pair do |key, type|
          if attributes.key?(attribute_map[key]) && attributes[attribute_map[key]].nil?
            transformed_hash[key.to_sym] = nil
          elsif type =~ /\AArray<(.*)>/i
            # check to ensure the input is an array given that the attribute
            # is documented as an array but the input is not
            if attributes[attribute_map[key]].is_a?(Array)
              transformed_hash[key.to_sym] = attributes[attribute_map[key]].map { |v|
                _deserialize(::Regexp.last_match(1), v)
              }
            end
          elsif !attributes[attribute_map[key]].nil?
            transformed_hash[key.to_sym] = _deserialize(type, attributes[attribute_map[key]])
          end
        end

        new(transformed_hash)
      end

      # Deserializes the data based on type
      # @param string type Data type
      # @param string value Value to be deserialized
      # @return [Object] Deserialized data
      def self._deserialize(type, value)
        case type.to_sym
        when :Time
          Time.parse(value)
        when :Date
          Date.parse(value)
        when :String
          value.to_s
        when :Integer
          value.to_i
        when :Float
          value.to_f
        when :Boolean
          if value.to_s =~ /\A(true|t|yes|y|1)\z/i
            true
          else
            false
          end

        when :Object
          # generic object (usually a Hash), return directly
          value
        when /\AArray<(?<inner_type>.+)>\z/
          inner_type = Regexp.last_match[:inner_type]
          value.map { |v| _deserialize(inner_type, v) }
        when /\AHash<(?<k_type>.+?), (?<v_type>.+)>\z/
          k_type = Regexp.last_match[:k_type]
          v_type = Regexp.last_match[:v_type]
          {}.tap do |hash|
            value.each do |k, v|
              hash[_deserialize(k_type, k)] = _deserialize(v_type, v)
            end
          end
          # model
        else
          # models (e.g. Pet) or oneOf
          klass = Algolia::AgentStudio.const_get(type)
          klass.respond_to?(:openapi_any_of) || klass.respond_to?(:openapi_one_of) ? klass.build(value) : klass
            .build_from_hash(value)
        end
      end

      # Returns the string representation of the object
      # @return [String] String presentation of the object
      def to_s
        to_hash.to_s
      end

      # to_body is an alias to to_hash (backward compatibility)
      # @return [Hash] Returns the object in the form of hash
      def to_body
        to_hash
      end

      def to_json(*_args)
        to_hash.to_json
      end

      # Returns the object in the form of hash
      # @return [Hash] Returns the object in the form of hash
      def to_hash
        hash = {}
        self.class.attribute_map.each_pair do |attr, param|
          value = send(attr)
          if value.nil?
            is_nullable = self.class.openapi_nullable.include?(attr)
            next if !is_nullable || (is_nullable && !instance_variable_defined?(:"@#{attr}"))
          end

          hash[param] = _to_hash(value)
        end

        hash
      end

      # Outputs non-array value in the form of hash
      # For object, use to_hash. Otherwise, just return the value
      # @param [Object] value Any valid value
      # @return [Hash] Returns the value in the form of hash
      def _to_hash(value)
        if value.is_a?(Array)
          value.compact.map { |v| _to_hash(v) }
        elsif value.is_a?(Hash)
          {}.tap do |hash|
            value.each { |k, v| hash[k] = _to_hash(v) }
          end
        elsif value.respond_to?(:to_hash)
          value.to_hash
        else
          value
        end
      end
    end
  end
end
